"""Score predictions generated by `query.py` and produce per-model reports.

For each model, we read the JSONL prediction file, compute the metrics
enabled in config.json, and write:

    outputs/reports/<model_id>.jsonl   # per-row scores
    outputs/reports/<model_id>.csv     # per-row scores (flat table)
    outputs/reports/summary.csv        # aggregated table over all models

The aggregated table mimics Table 2 of the paper, broken down by
question_type (numerical / non-numerical).
"""

from __future__ import annotations

import argparse
import glob
import json
import os
from typing import Dict, List

import pandas as pd
from tqdm.auto import tqdm

from metrics import (
    GPTJudge,
    SemanticMatcher,
    answer_rate,
    exact_match,
    is_numerical_answer,
    is_refusal,
    numerical_accuracy,
    rouge1_f1,
)


# ---------------------------------------------------------------------------
# Scoring a single prediction file
# ---------------------------------------------------------------------------

def _read_jsonl(path: str) -> List[dict]:
    rows = []
    with open(path, "r", encoding="utf-8") as f:
        for line in f:
            line = line.strip()
            if line:
                rows.append(json.loads(line))
    return rows


def score_predictions(
    prediction_path: str,
    metrics_cfg: Dict[str, bool],
    *,
    numerical_tolerance: float = 0.02,
    embedding_model: str = "text-embedding-3-small",
    judge_model: str = "gpt-4o-mini",
) -> pd.DataFrame:
    rows = _read_jsonl(prediction_path)

    semantic = SemanticMatcher(embedding_model) if metrics_cfg.get("semantic_match") else None
    judge = GPTJudge(judge_model) if metrics_cfg.get("gpt_judge") else None

    scored: List[dict] = []
    for r in tqdm(rows, desc=f"scoring {os.path.basename(prediction_path)}"):
        pred = r.get("response", "")
        ref = r.get("reference", "")
        q = r.get("question", "")
        ctx = r.get("context", "") or ""

        # question_type from loader may not distinguish true/false from text;
        # we use the reference format to decide for numerical accuracy.
        is_num = r.get("question_type") == "numerical" or (
            r.get("dataset") == "census" and is_numerical_answer(ref)
        )

        record = {
            "id": r["id"],
            "dataset": r.get("dataset"),
            "rucc_group": r.get("rucc_group"),
            "dimension": r.get("dimension"),
            "question_type": "numerical" if is_num else "non_numerical",
            "refusal": is_refusal(pred),
            "model": r.get("model"),
        }

        if metrics_cfg.get("exact_match", True):
            record["exact_match"] = exact_match(pred, ref)
        if metrics_cfg.get("rouge1", True):
            record["rouge1"] = rouge1_f1(pred, ref)
        if metrics_cfg.get("numerical_accuracy", True):
            record["numerical_accuracy"] = (
                numerical_accuracy(pred, ref, tolerance=numerical_tolerance) if is_num else None
            )
        if semantic is not None:
            try:
                record["semantic_match"] = semantic.score(pred, ref) if pred and ref else 0.0
            except Exception as e:  # pragma: no cover
                record["semantic_match"] = None
                record["semantic_error"] = str(e)
        if judge is not None and not is_num:
            try:
                record["gpt_judge"] = judge.score(q, ref, pred, context=ctx)
            except Exception as e:  # pragma: no cover
                record["gpt_judge"] = None
                record["gpt_judge_error"] = str(e)

        scored.append(record)

    return pd.DataFrame(scored)


# ---------------------------------------------------------------------------
# Aggregation
# ---------------------------------------------------------------------------

def aggregate(df: pd.DataFrame) -> pd.DataFrame:
    """Collapse per-row scores into per-model, per-question-type numbers."""
    metric_cols = [c for c in df.columns if c in {
        "exact_match", "rouge1", "semantic_match", "numerical_accuracy", "gpt_judge"
    }]
    rows = []
    for (model, qtype), sub in df.groupby(["model", "question_type"]):
        row = {
            "model": model,
            "question_type": qtype,
            "n": len(sub),
            "answer_rate": 1.0 - sub["refusal"].mean(),
        }
        for m in metric_cols:
            if m in sub.columns:
                vals = sub[m].dropna()
                row[m] = float(vals.mean()) if len(vals) else None
        rows.append(row)
    return pd.DataFrame(rows).sort_values(["model", "question_type"])


# ---------------------------------------------------------------------------
# Entry points
# ---------------------------------------------------------------------------

def evaluate_all(
    output_dir: str = "outputs",
    config: Dict | None = None,
) -> pd.DataFrame:
    config = config or {}
    metrics_cfg = config.get("metrics", {
        "exact_match": True, "rouge1": True, "semantic_match": True,
        "numerical_accuracy": True, "gpt_judge": True, "answer_rate": True,
    })
    eval_cfg = config.get("evaluate", {})

    os.makedirs(os.path.join(output_dir, "reports"), exist_ok=True)
    pred_files = sorted(glob.glob(os.path.join(output_dir, "predictions", "*.jsonl")))
    if not pred_files:
        raise FileNotFoundError(
            f"No prediction files under {output_dir}/predictions. Run query first."
        )

    all_scored = []
    for pf in pred_files:
        model_id = os.path.splitext(os.path.basename(pf))[0]
        df = score_predictions(
            pf,
            metrics_cfg,
            numerical_tolerance=eval_cfg.get("numerical_tolerance", 0.02),
            embedding_model=eval_cfg.get("embedding_model", "text-embedding-3-small"),
            judge_model=eval_cfg.get("judge_model", "gpt-4o-mini"),
        )
        df["model"] = model_id
        all_scored.append(df)
        df.to_csv(os.path.join(output_dir, "reports", f"{model_id}.csv"), index=False)
        df.to_json(
            os.path.join(output_dir, "reports", f"{model_id}.jsonl"),
            orient="records", lines=True, force_ascii=False,
        )

    combined = pd.concat(all_scored, ignore_index=True)
    summary = aggregate(combined)
    summary_path = os.path.join(output_dir, "reports", "summary.csv")
    summary.to_csv(summary_path, index=False)
    print(f"Wrote summary to {summary_path}")
    print(summary.to_string(index=False))
    return summary


if __name__ == "__main__":
    parser = argparse.ArgumentParser(description="Evaluate LocalBench predictions.")
    parser.add_argument("--config", default="config.json")
    parser.add_argument("--output-dir", default=None)
    args = parser.parse_args()

    with open(args.config) as f:
        cfg = json.load(f)
    out_dir = args.output_dir or cfg.get("output_dir", "outputs")
    evaluate_all(output_dir=out_dir, config=cfg)
